using System.Linq; using System.Data.Entity; using System.Windows; using System.Windows.Controls; using WarehouseManagement.ApplicationData;
namespace WarehouseManagement.Pages { public partial class WarehouseProductsPage:Page { public WarehouseProductsPage(){InitializeComponent(); LoadProducts();} void LoadProducts(){lvAdminProducts.ItemsSource=AppConnect.model01.Products.Include("Categories").Include("StockBalances").ToList();} private void btnBack_Click(object s,RoutedEventArgs e){AppFrame.frmMain.GoBack();} private void btnAdd_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new ProductCardPage(null));} private void lvAdminProducts_MouseDoubleClick(object s,System.Windows.Input.MouseButtonEventArgs e){if(lvAdminProducts.SelectedItem is Products p) AppFrame.frmMain.Navigate(new ProductCardPage(p));} private void btnDelete_Click(object s,RoutedEventArgs e){if(!(lvAdminProducts.SelectedItem is Products p)){MessageBox.Show("Выберите товар");return;} p.IsActive=false; AppConnect.model01.SaveChanges(); WarehouseService.Log("Удаление","Products",p.ProductID,"Товар деактивирован"); LoadProducts();} private void btnUsers_Click(object s,RoutedEventArgs e){AppFrame.frmMain.Navigate(new AdminUsersPage());}}}
